        .init(es: "Sal. Tu cuerpo lleva días esperando que le hagas caso.", en: "Go. Your body has been waiting days for you to listen."),
        .init(es: "Corre. Porque el movimiento es el lenguaje de los vivos.", en: "Run. Because movement is the language of the living."),
        .init(es: "No necesitas música. No necesitas ruta. Solo necesitas salir.", en: "You don't need music. You don't need a route. Just get out."),
        .init(es: "Cada run te acerca un paso a quien quieres ser.", en: "Every run gets you one step closer to who you want to be."),
        .init(es: "Hoy el sillón no gana. Tú sí.", en: "Today the couch doesn't win. You do."),
        .init(es: "Corre. La versión más fuerte de ti ya está calentando.", en: "Run. The strongest version of you is already warming up."),
        .init(es: "Tu pacepal sabe cuándo corriste. Y cuándo no.", en: "Your pacepal knows when you ran. And when you didn't."),
        .init(es: "Sal antes de que el día decida por ti.", en: "Go before the day decides for you."),
        .init(es: "El run de hoy no es opcional. Los otros 65 días lo necesitan.", en: "Today's run isn't optional. The other 65 days need it."),
