        .init(es: "Sal. No para quemar calorías, sino para recordar que puedes.", en: "Go. Not to burn calories, but to remember you can."),
        .init(es: "Los 66 días no te piden velocidad. Te piden constancia.", en: "The 66 days don't ask for speed. They ask for consistency."),
        .init(es: "Cada kilómetro es silencio bien aprovechado.", en: "Every kilometer is silence well spent."),
        .init(es: "Tus zapatillas no son de adorno. Deja que lo demuestren.", en: "Your shoes aren't decoration. Let them prove it."),
        .init(es: "El run de hoy es la racha de mañana. No la rompas.", en: "Today's run is tomorrow's streak. Don't break it."),
        .init(es: "Tu pacepal festeja cada km como si fuera el primero.", en: "Your pacepal celebrates every km like it's the first."),
        .init(es: "Sal. Nadie te va a aplaudir desde el sillón.", en: "Go. Nobody's going to clap for you from the couch."),
        .init(es: "Corre aunque no hayas dormido bien. El cuerpo se ajusta.", en: "Run even if you slept badly. Your body adjusts."),
        .init(es: "Afuera está el km que necesitas. Aquí dentro, solo pretextos.", en: "The km you need is outside. In here, there's only excuses."),
        .init(es: "El hábito que buscas se construye corriendo, no pensando en correr.", en: "The habit you want is built by running, not thinking about running."),
