        .init(es: "Tu pacepal guarda cada paso. No le falles.", en: "Your pacepal saves every step. Don't let it down."),
        .init(es: "Corre. El mundo exterior siempre gana al interior.", en: "Run. The outside world always beats the indoors."),
        .init(es: "Cinco kilómetros o quinientos metros. Los dos son un sí.", en: "Five kilometers or five hundred meters. Both are a yes."),
