        .init(es: "Sal. Tu pacepal lleva rato calentando sin ti.", en: "Go. Your pacepal has been warming up without you."),
        .init(es: "El hábito es la suma de muchos días que dijeron que sí.", en: "Habit is the sum of many days that said yes."),
        .init(es: "Tus piernas recuerdan cada kilómetro. Dales más razones.", en: "Your legs remember every kilometer. Give them more reasons."),
