        .init(es: "Corre. Tu cerebro produce las mejores ideas en movimiento.", en: "Run. Your brain produces its best ideas in motion."),
        .init(es: "No hay atajos en los 66 días. Solo pasos hacia adelante.", en: "There are no shortcuts in the 66 days. Only steps forward."),
