        .init(es: "Tu pacepal tiene energía acumulada. Dale salida.", en: "Your pacepal has stored-up energy. Let it out."),
        .init(es: "Corre. No existe versión mejorada de ti que no lo haga.", en: "Run. There's no upgraded version of you that doesn't."),
        .init(es: "El run de hoy es el descanso que mereces mañana.", en: "Today's run is the rest you deserve tomorrow."),
