        .init(es: "Sal. La calle no te va a juzgar el ritmo.", en: "Go. The street won't judge your pace."),
        .init(es: "Cada run es una promesa que te cumples a ti mismo.", en: "Every run is a promise you keep to yourself."),
        .init(es: "No te compares con nadie. Compárate con ayer.", en: "Don't compare yourself to anyone. Compare with yesterday."),
        .init(es: "Tu cuerpo fue diseñado para moverse. No para el escritorio.", en: "Your body was designed to move. Not for a desk."),
