        .init(es: "El run que pospones es el hábito que nunca llega.", en: "The run you postpone is the habit that never arrives."),
        .init(es: "Sal. Afuera hay aire, kilómetros y razones para estar bien.", en: "Go. Outside there's air, kilometers, and reasons to feel good."),
        .init(es: "Corre. Porque el movimiento hace lo que el silencio no puede.", en: "Run. Because movement does what silence can't."),
        .init(es: "Un km hoy vale más que diez que no existen.", en: "One km today is worth more than ten that don't exist."),
        .init(es: "Tu pacepal guarda memoria de cada esfuerzo. No lo borres.", en: "Your pacepal remembers every effort. Don't erase it."),
        .init(es: "Sal aunque solo puedas 10 minutos. 10 minutos cambian algo.", en: "Go even if you only have 10 minutes. 10 minutes change something."),
        .init(es: "El run no te pide que seas atleta. Solo que aparezcas.", en: "The run doesn't ask you to be an athlete. Just to show up."),
